import{_ as a,o as i,c as t,a2 as r}from"./chunks/framework.N9BN-Nr4.js";const m=JSON.parse('{"title":"Horde Magic Wiki Summary","description":"","frontmatter":{},"headers":[],"relativePath":"formats/horde/sources/horde-magic-wiki.md","filePath":"formats/horde/sources/horde-magic-wiki.md","lastUpdated":1782025909000}'),o={name:"formats/horde/sources/horde-magic-wiki.md"};function l(s,e,n,d,h,c){return i(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="horde-magic-wiki-summary" tabindex="-1">Horde Magic Wiki Summary <a class="header-anchor" href="#horde-magic-wiki-summary" aria-label="Permalink to &quot;Horde Magic Wiki Summary&quot;">​</a></h1><p>Source: <a href="https://mtg.fandom.com/wiki/Horde_Magic#Rules_for_The_Horde" target="_blank" rel="noreferrer">https://mtg.fandom.com/wiki/Horde_Magic#Rules_for_The_Horde</a></p><p>This source summarizes Horde Magic as a casual multiplayer format where all players work together against an automated Horde deck.</p><h2 id="format-snapshot" tabindex="-1">Format Snapshot <a class="header-anchor" href="#format-snapshot" aria-label="Permalink to &quot;Format Snapshot&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Field</th><th>Value</th></tr></thead><tbody><tr><td>DCI sanctioned</td><td>No</td></tr><tr><td>Paper</td><td>No official sanctioning</td></tr><tr><td>Magic Online</td><td>No</td></tr><tr><td>Magic Arena</td><td>No</td></tr><tr><td>Type</td><td>Constructed casual variant</td></tr><tr><td>Multiplayer</td><td>Yes</td></tr></tbody></table><h2 id="format-goals" tabindex="-1">Format Goals <a class="header-anchor" href="#format-goals" aria-label="Permalink to &quot;Format Goals&quot;">​</a></h2><h3 id="spirit" tabindex="-1">Spirit <a class="header-anchor" href="#spirit" aria-label="Permalink to &quot;Spirit&quot;">​</a></h3><p>Horde Magic is casual and social. If a rule or card interaction makes the game less fun, the table should agree on a practical fix. Cycling or replacing problematic cards is a common solution.</p><h3 id="flavor" tabindex="-1">Flavor <a class="header-anchor" href="#flavor" aria-label="Permalink to &quot;Flavor&quot;">​</a></h3><p>The original theme was a zombie apocalypse. The automated rules fit zombies well because the Horde should make as few choices as possible. Other thematic Hordes can work as long as the deck remains flavorful and functional.</p><h2 id="participants" tabindex="-1">Participants <a class="header-anchor" href="#participants" aria-label="Permalink to &quot;Participants&quot;">​</a></h2><p>Horde Magic has two sides:</p><ul><li><strong>The Horde</strong>: An automated deck.</li><li><strong>The Survivors</strong>: The human players acting cooperatively.</li></ul><h2 id="win-conditions" tabindex="-1">Win Conditions <a class="header-anchor" href="#win-conditions" aria-label="Permalink to &quot;Win Conditions&quot;">​</a></h2><p>The Horde wins if:</p><ul><li>The Survivors&#39; shared life total is reduced to 0 or less.</li></ul><p>The Survivors win if:</p><ul><li>The Horde has no cards in its library.</li><li>The Horde has no cards in hand.</li><li>The Horde controls no creatures.</li></ul><h2 id="rules-for-the-horde" tabindex="-1">Rules For The Horde <a class="header-anchor" href="#rules-for-the-horde" aria-label="Permalink to &quot;Rules For The Horde&quot;">​</a></h2><ul><li>The Horde has no player and pilots itself.</li><li>Any choice the Horde must make should be made as randomly as possible.</li><li>The Horde has infinite mana at all times.</li><li>At the start of the Horde&#39;s turn, reveal cards from the top of its library until a non-token card is revealed.</li><li>Cast all revealed tokens, then cast the revealed non-token card.</li><li>If applicable, the Horde also casts cards from its graveyard and hand.</li><li>All Horde creatures have haste and must attack each turn if able.</li><li>The Horde has no life total.</li><li>Damage dealt to the Horde, or life loss inflicted on the Horde, causes it to mill that many cards instead.</li><li>Lifelink still works for players, but the Horde cannot &quot;unmill&quot; cards.</li></ul><h2 id="rules-for-the-survivors" tabindex="-1">Rules For The Survivors <a class="header-anchor" href="#rules-for-the-survivors" aria-label="Permalink to &quot;Rules For The Survivors&quot;">​</a></h2><ul><li>The Survivors take three setup turns before the Horde gets its first turn.</li><li>After setup, turns alternate normally.</li><li>The Survivors are a team and take their turns simultaneously, similar to Two-Headed Giant.</li><li>The Survivors attack and block as a team.</li><li>Each Survivor contributes 20 life to the shared life total.</li></ul><h2 id="adjusting-difficulty" tabindex="-1">Adjusting Difficulty <a class="header-anchor" href="#adjusting-difficulty" aria-label="Permalink to &quot;Adjusting Difficulty&quot;">​</a></h2><p>The source suggests tuning difficulty by changing:</p><ul><li>Number of setup turns.</li><li>Life contributed by each Survivor.</li><li>Size of the random portion exiled from the Horde deck before the first turn.</li><li>Horde deck construction.</li><li>Horde sideboard.</li><li>Whether random Horde choices are replaced by Survivor consensus.</li><li>Whether tokens remain in the graveyard instead of ceasing to exist.</li><li>Whether Survivors can attack during setup turns.</li><li>Token-to-non-token ratio.</li></ul><h2 id="horde-deck-construction" tabindex="-1">Horde Deck Construction <a class="header-anchor" href="#horde-deck-construction" aria-label="Permalink to &quot;Horde Deck Construction&quot;">​</a></h2><ul><li>A default Horde deck is 100 cards.</li><li>About 60 cards should be tokens.</li><li>About 40 cards should be regular Magic cards.</li><li>Cards should avoid forcing the Horde to make choices.</li><li>Cards should be thematic, flavorful, and fun.</li></ul><h2 id="ban-list" tabindex="-1">Ban List <a class="header-anchor" href="#ban-list" aria-label="Permalink to &quot;Ban List&quot;">​</a></h2><p>Peter Knudson posted a rough ban list to remove cards that create automatic wins against the Horde.</p><ul><li>Aether Flash</li><li>Aurification</li><li>Barbed Foliage</li><li>Caltrops</li><li>Crawlspace</li><li>Dueling Grounds</li><li>Dread</li><li>Elesh Norn, Grand Cenobite</li><li>Ensnaring Bridge</li><li>Eradicate</li><li>Grindstone</li><li>Haunting Echoes</li><li>Island Sanctuary</li><li>Lethal Vapors</li><li>Leyline of Singularity</li><li>Magus of the Moat</li><li>Mind Funeral</li><li>Moat</li><li>No Mercy</li><li>Platinum Angel</li><li>Platinum Emperion</li><li>Silent Arbiter</li><li>Solitary Confinement</li><li>Stormtide Leviathan</li><li>Surgical Extraction</li><li>Tainted Aether</li><li>Teferi&#39;s Moat</li><li>Time Stretch</li><li>Trepanation Blade</li><li>Urabrask the Hidden</li></ul><h2 id="connections" tabindex="-1">Connections <a class="header-anchor" href="#connections" aria-label="Permalink to &quot;Connections&quot;">​</a></h2><p>The wiki compares Horde Magic to World of Warcraft Raid decks and the Theros Challenge Decks.</p><h2 id="references-listed-by-source" tabindex="-1">References Listed By Source <a class="header-anchor" href="#references-listed-by-source" aria-label="Permalink to &quot;References Listed By Source&quot;">​</a></h2><ul><li>Peter Knudson, &quot;Horde Magic: A New Way to Play Magic and Survive Zombie Invasions&quot;</li><li>Peter Knudson, &quot;Horde Magic: An Open Source Project&quot;</li><li>Adam Styborski, &quot;Up Up Down Down Left Right Left Right B A Shuffle&quot;</li><li>Adam Styborski, &quot;Then We Will Fight in the Shade!&quot;</li><li>Adam Styborski, &quot;Stitched in the Middle with You&quot;</li></ul>',34)])])}const f=a(o,[["render",l]]);export{m as __pageData,f as default};
